// 初始化内置词库
async function initBuiltInWordlists() {
  for (const list of BUILT_IN_WORDLISTS) {
    const existing = await db.get(STORE_WORDS, list.id);
    if (!existing) {
      await db.put(STORE_WORDS, list);
    }
  }
}
